mapper.select:
SELECT co.* from fc_collection co left join
uc_customer cu on co.customerId = cu.id WHERE 1 = 1


    AND (
    co.`code` LIKE concat('%', #{query.name}, '%') OR
    cu.`code` LIKE concat('%', #{query.name}, '%') OR
    cu.`name` LIKE concat('%', #{query.name}, '%')
    )



    AND co.`issueDate`  >=  #{query.startDate}


    AND co.`issueDate`  <=  #{query.endDate}


ORDER BY co.createdTime DESC
